export function createWorkbenchCommands(transport: WorkbenchCommandTransport): WorkbenchCommands { return {
  async getAppStatus() { return loadAppStatus(transport); },
  async getPaperMarketHostStatus() { return parsePaperMarketHostStatusV1(await transport.invoke("get_paper_market_host_status_v1")); },
  async getPaperMarketRuntime() { return parsePaperMarketRuntimeV1(await transport.invoke("get_paper_market_runtime_v1")); },
  async getPaperStrategyRuntime() { return parsePaperStrategyRuntimeV1(await transport.invoke("get_paper_strategy_runtime_v1")); },
  async startPaperRunner(runner){return parsePaperMarketHostStatusV1(await transport.invoke("start_public_paper_market_host_v1",{explicitNetworkApproval:true,runner}));},
  async startPublicPaperMarketHost(slug, explicitNetworkApproval) { return parsePaperMarketHostStatusV1(await transport.invoke("start_public_paper_market_host_v1", { slug, explicitNetworkApproval })); },
  async stopPublicPaperMarketHost() { return parsePaperMarketHostStatusV1(await transport.invoke("stop_public_paper_market_host_v1")); },
  async getPaperReplay(page) { return parsePaperReplayPageV1(await transport.invoke("get_paper_replay_v1", { page: page.page, pageSize: page.pageSize })); },
  async listPaperSessions() { return parsePaperSessionsV1(await transport.invoke("list_paper_sessions_v1")); },
  async startPaperSession(request) { return parsePaperSessionsV1([await transport.invoke("start_paper_session_v1", { request })])[0]!; },
  async getPaperSessionStatus(sessionId) { return parsePaperSessionsV1([await transport.invoke("get_paper_session_status_v1", { sessionId })])[0]!; },
  async stopPaperSession(sessionId) { return parsePaperSessionsV1([await transport.invoke("stop_paper_session_v1", { sessionId })])[0]!; },
  async resumePaperSession(sessionId) { return parsePaperSessionsV1([await transport.invoke("resume_paper_session_v1", { sessionId })])[0]!; },
  async getPaperSessionDetail(sessionId){return parsePaperSessionDetailV1(await transport.invoke("get_paper_session_detail_v1",{sessionId}));},
  async submitPaperOrder(sessionId,request){return paperOrder(await transport.invoke("submit_paper_order_v1",{sessionId,request}));},
  async cancelPaperOrder(sessionId,orderId,reason){return paperOrder(await transport.invoke("cancel_paper_order_v1",{sessionId,orderId,reason}));},
  async repricePaperOrder(sessionId,orderId,replacement){return paperOrder(await transport.invoke("reprice_paper_order_v1",{sessionId,orderId,replacement}));},
  async expirePaperOrders(sessionId){return Object.freeze(array(await transport.invoke("expire_paper_orders_v1",{sessionId}),"expired orders").map((value,index)=>paperOrder(value,`expired orders[${index}]`)));},
  async settlePaperMarket(sessionId,marketId,winningToken,evidenceMode){const input=object(await transport.invoke("settle_paper_market_v1",{sessionId,marketId,winningToken,evidenceMode}),"settlement");exact(input,["marketId","winningToken","payout","settledAtUtc"],"settlement");return{marketId:text(input.marketId,"marketId"),winningToken:paperToken(input.winningToken,"winningToken"),payout:text(input.payout,"payout"),settledAtUtc:utc(input.settledAtUtc,"settledAtUtc")};},
  async getPaperSystemControl() { return parsePaperSystemControlV1(await transport.invoke("get_paper_system_control_v1")); },
  async setPaperKillSwitch(enabled, reason) { return parsePaperSystemControlV1(await transport.invoke("set_paper_kill_switch_v1", { enabled, reason })); },
  async listStrategyDefinitions() { return parseStrategyDefinitionsV1(await transport.invoke("list_strategy_definitions_v1")); },
  async listStrategyVersions(strategyId) { return parseStrategyVersionsV1(await transport.invoke("list_strategy_versions_v1", { strategyId })); },
  async getStrategyVersion(strategyId, version) { return parseStrategyVersionV1(await transport.invoke("get_strategy_version_v1", { strategyId, version })); },
  async validateStrategyParameters(strategyId, input) { return parseStrategyValidationV1(await transport.invoke("validate_strategy_parameters_v1", { strategyId, parameters: input })); },
  async saveStrategyVersion(value) { return parseStrategyVersionV1(await transport.invoke("save_strategy_version_v1", { value })); },
  async deleteStrategyVersion(strategyId,version){return deletionReceipt(await transport.invoke("delete_strategy_version_v1",{strategyId,version,confirmation:`${strategyId}:${version}`}),"strategy-version");},
  async registerDatasetSource(request) { return parseRegisteredDatasetSourceV1(await transport.invoke("register_dataset_source_v1", { request })); },
  async normalizeRawDataset(request) { return parseNormalizedDatasetPublicationV1(await transport.invoke("normalize_raw_dataset_v1", { request })); },
  async scanDatasets() { return parseDatasetScanV1(await transport.invoke("scan_datasets_v1")); },
  async listDatasets() { return parseDatasetListV1(await transport.invoke("list_datasets_v1")); },
  async getDataset(datasetId, versionHash) { return parseDatasetDetailV1(await transport.invoke("get_dataset_v1", { datasetId, versionHash })); },
  async validateDatasetSelection(selection) { return parseValidatedDatasetSelectionV1(await transport.invoke("validate_dataset_selection_v1", { selection })); },
  async deleteDataset(datasetId,versionHash){return deletionReceipt(await transport.invoke("delete_dataset_v1",{datasetId,versionHash,confirmation:`${datasetId}:${versionHash}`}),"dataset");},
  async startBacktest(request) { return parseBacktestJobV1(await transport.invoke("start_backtest_v1", { request })); }, async getBacktestJob(runId) { return parseBacktestJobV1(await transport.invoke("get_backtest_job_v1", { runId })); }, async listBacktestJobs() { return parseBacktestJobsV1(await transport.invoke("list_backtest_jobs_v1")); }, async stopBacktest(runId) { return parseBacktestJobV1(await transport.invoke("stop_backtest_v1", { runId })); },async deleteBacktest(runId){return deletionReceipt(await transport.invoke("delete_backtest_v1",{runId,confirmation:runId}),"backtest");}, async getBacktestResult(runId) { return parseBacktestResultV1(await transport.invoke("get_backtest_result_v1", { runId })); },
  async getBacktestDecisions(runId,page){return parseBacktestEventPageV1(await transport.invoke("get_backtest_decisions_v1",{runId,page}));},
  async getBacktestOrders(runId,page){return parseBacktestEventPageV1(await transport.invoke("get_backtest_orders_v1",{runId,page}));},
  async getBacktestFills(runId,page){return parseBacktestEventPageV1(await transport.invoke("get_backtest_fills_v1",{runId,page}));},
  async getBacktestSettlements(runId,page){return parseBacktestEventPageV1(await transport.invoke("get_backtest_settlements_v1",{runId,page}));},
  async getBacktestEquity(runId,page){return parseEquityPageV1(await transport.invoke("get_backtest_equity_v1",{runId,page}));},
  async getBacktestReplay(runId,page){return parseBacktestEventPageV1(await transport.invoke("get_backtest_replay_v1",{runId,page}));},
  async compareBacktests(runIds){return parseRunComparisonsV1(await transport.invoke("compare_backtests_v1",{runIds}));},
  async getSystemHealth(){return parseSystemHealthV1(await transport.invoke("get_system_health_v1"));},
  async listSystemIncidents(page){return parseSystemIncidentPageV1(await transport.invoke("list_system_incidents_v1",{page}));},
}; }
